keyframes_css:
@keyframes rise {
  0% {
    transform: translateY(80px);
    opacity: 0.3;
  }
  50% {
    opacity: 1;
  }
  100% {
    transform: translateY(-80px);
    opacity: 0.3;
  }
}

@keyframes float {
  0%, 100% {
    transform: translateX(0px) scale(1);
  }
  50% {
    transform: translateX(20px) scale(0.8);
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: linear-gradient(to bottom, #1a1a2e, #0f3460);
  border-radius: 10px;
  overflow: hidden;
  position: relative;
}

.demo-stage::before {
  content: '';
  position: absolute;
  bottom: 20px;
  left: 50%;
  transform: translateX(-50%);
  width: 80px;
  height: 60px;
  background: radial-gradient(ellipse at 30% 30%, #00ff88, #00cc66);
  border-radius: 50%;
  box-shadow: 0 0 20px rgba(0, 255, 136, 0.6), inset -2px -2px 10px rgba(0, 0, 0, 0.3);
  animation: rise 3s ease-in-out infinite;
}

.demo-stage::after {
  content: '';
  position: absolute;
  top: 30px;
  left: 50%;
  transform: translateX(-50%);
  width: 60px;
  height: 40px;
  background: radial-gradient(ellipse at 40% 40%, #00ffaa, #00dd77);
  border-radius: 50%;
  box-shadow: 0 0 15px rgba(0, 255, 170, 0.5), inset -1px -1px 8px rgba(0, 0, 0, 0.2);
  animation: rise 3.5s ease-in-out infinite 0.5s;
  opacity: 0.7;
}

.liquid-drop {
  position: absolute;
  width: 20px;
  height: 20px;
  background: radial-gradient(circle at 30% 30%, #00ffcc, #00aa88);
  border-radius: 50%;
  box-shadow: 0 0 10px rgba(0, 255, 204, 0.7);
  animation: rise 2.8s ease-in-out infinite;
}

.liquid-drop:nth-child(1) {
  left: 40px;
  animation-delay: 0.2s;
}

.liquid-drop:nth-child(2) {
  left: 90px;
  animation-delay: 0.8s;
}

.liquid-drop:nth-child(3) {
  left: 140px;
  animation-delay: 1.4s;
}

@keyframes fall {
  0% {
    transform: translateY(-20px);
    opacity: 1;
  }
  100% {
    transform: translateY(180px);
    opacity: 0;
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: linear-gradient(180deg, #1a1a2e 0%, #16213e 100%);
  border-radius: 8px;
  overflow: hidden;
  position: relative;
}

.demo-stage::before,
.demo-stage::after {
  content: '';
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  animation: fall 1.5s infinite ease-in;
}

.demo-stage::before {
  left: 30%;
  animation-delay: 0s;
}

.demo-stage::after {
  left: 60%;
  animation-delay: 0.5s;
}

.demo-stage .drop1 {
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  left: 45%;
  animation: fall 1.5s infinite ease-in;
  animation-delay: 1s;
}

.demo-stage .drop2 {
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  left: 75%;
  animation: fall 1.5s infinite ease-in;
  animation-delay: 0.25s;
}

.demo-stage .drop3 {
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  left: 15%;
  animation: fall 1.5s infinite ease-in;
  animation-delay: 0.75s;
}
